-- Frontend-aligned final local seed for product reset
-- Reset product-related data, extend schema if needed, then insert enriched catalog rows.
-- Based on frontend_test_seed.sql source rows and current frontend category/type rules.
BEGIN;

-- 0) Optional typo fix: rename demension_image_path -> dimension_image_path if an old column exists.
DO $$ BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'products' AND column_name = 'demension_image_path')
     AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'products' AND column_name = 'dimension_image_path') THEN
    EXECUTE 'ALTER TABLE products RENAME COLUMN demension_image_path TO dimension_image_path';
  END IF;
END $$;

-- 1) Extend products schema to match frontend product payload expectations.
ALTER TABLE products ADD COLUMN IF NOT EXISTS original_price INTEGER;
ALTER TABLE products ADD COLUMN IF NOT EXISTS brand VARCHAR(100);
ALTER TABLE products ADD COLUMN IF NOT EXISTS badge VARCHAR(50);
ALTER TABLE products ADD COLUMN IF NOT EXISTS label VARCHAR(100);
ALTER TABLE products ADD COLUMN IF NOT EXISTS type_slug VARCHAR(100);
ALTER TABLE products ADD COLUMN IF NOT EXISTS attributes TEXT;
ALTER TABLE products ADD COLUMN IF NOT EXISTS detail_content TEXT;
ALTER TABLE products ADD COLUMN IF NOT EXISTS gallery_images TEXT;
ALTER TABLE products ADD COLUMN IF NOT EXISTS dimension_image_path TEXT;

-- 2) Reset product-related tables and impacted transactional rows. Local test DB 기준입니다.
CREATE TEMP TABLE tmp_seed_target_orders AS
SELECT DISTINCT oi.order_id
FROM order_items oi
JOIN products p ON p.product_id = oi.product_id;

DELETE FROM cart_items
WHERE product_id IN (SELECT product_id FROM products);

DELETE FROM reviews
WHERE product_id IN (SELECT product_id FROM products);

DELETE FROM order_items
WHERE product_id IN (SELECT product_id FROM products);

DELETE FROM payments
WHERE order_id IN (SELECT order_id FROM tmp_seed_target_orders);

DELETE FROM orders
WHERE order_id IN (SELECT order_id FROM tmp_seed_target_orders);

DELETE FROM product_stocks;
DELETE FROM products;
DROP TABLE tmp_seed_target_orders;

-- 3) Ensure categories exist. frontend route/category labels depend on these names.
INSERT INTO category (name) VALUES
  ('소파'),
  ('침대/매트리스'),
  ('식탁/테이블/의자'),
  ('책상'),
  ('주방가구'),
  ('주방용품'),
  ('화분/식물')
ON CONFLICT (name) DO NOTHING;

WITH product_seed(
  name,
  price,
  original_price,
  img_path,
  brand,
  badge,
  label,
  type_slug,
  attributes,
  detail_content,
  gallery_images,
  dimension_image_path,
  category_name
) AS (
