),
resolved_seed AS (
  SELECT
    ps.*,
    c.id AS category_id,
    'SEED-' || LPAD(ROW_NUMBER() OVER (ORDER BY ps.category_name, ps.name)::text, 4, '0') AS product_code
  FROM product_seed ps
  JOIN category c ON c.name = ps.category_name
)
INSERT INTO products (
  product_code,
  name,
  price,
  original_price,
  img_path,
  brand,
  badge,
  label,
  type_slug,
  attributes,
  detail_content,
  gallery_images,
  dimension_image_path,
  created_at,
  category_id
)
SELECT
  rs.product_code,
  rs.name,
  rs.price,
  rs.original_price,
  rs.img_path,
  rs.brand,
  NULLIF(rs.badge, ''),
  rs.label,
  rs.type_slug,
  rs.attributes,
  rs.detail_content,
  rs.gallery_images,
  rs.dimension_image_path,
  NOW(),
  rs.category_id
FROM resolved_seed rs;

INSERT INTO product_stocks (product_id, quantity, updated_at)
SELECT product_id, 10, NOW()
FROM products;

COMMIT;

SELECT COUNT(*) AS category_count FROM category;
SELECT COUNT(*) AS product_count FROM products;
SELECT COUNT(*) AS product_stock_count FROM product_stocks;